#define BLOCK_SIZE 16

kernel void lud_diagonal(global float* a, const int size, const int offset)
{
    int i, j, k;
    int idx = get_global_id(0);

    // Only thread 0 executes the sequential diagonal block update
    if (idx != 0) return;

    for (i = 0; i < BLOCK_SIZE; i++) {
        // Upper triangle: Update row i, columns i to BS-1
        for (j = i; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < i; k++) {
                sum += a[(offset + i) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
            }
            a[(offset + i) * size + (offset + j)] -= sum;
        }

        float inv_diag = 1.0f / a[(offset + i) * size + (offset + i)];

        // Lower triangle: Update column i, rows i+1 to BS-1
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < i; k++) {
                sum += a[(offset + j) * size + (offset + k)] * a[(offset + k) * size + (offset + i)];
            }
            a[(offset + j) * size + (offset + i)] = (a[(offset + j) * size + (offset + i)] - sum) * inv_diag;
        }
    }
}

kernel void lud_perimeter(global float* a, const int size, const int offset)
{
    int idx = get_global_id(0);
    int total_chunks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx >= total_chunks * 2) return;

    int chunk_idx;
    int is_upper = 0;

    if (idx < total_chunks) {
        chunk_idx = idx;
        is_upper = 1;
    } else {
        chunk_idx = idx - total_chunks;
        is_upper = 0;
    }

    int i, j, k;
    int i_global, j_global;
    float sum;

    // Local array for pivot block
    float local_temp[BLOCK_SIZE * BLOCK_SIZE];

    // Load pivot block (offset, offset)
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            local_temp[i * BLOCK_SIZE + j] = a[(offset + i) * size + (offset + j)];
        }
    }

    if (is_upper) {
        j_global = offset + BLOCK_SIZE * (chunk_idx + 1);

        for (j = 0; j < BLOCK_SIZE; j++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += local_temp[i * BLOCK_SIZE + k] * a[(offset + k) * size + (j_global + j)];
                }
                a[(offset + i) * size + (j_global + j)] -= sum;
            }
        }
    } else {
        i_global = offset + BLOCK_SIZE * (chunk_idx + 1);

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum = 0.0f;
                for (k = 0; k < j; k++) {
                    sum += a[(i_global + i) * size + (offset + k)] * local_temp[k * BLOCK_SIZE + j];
                }
                float diag = a[(offset + j) * size + (offset + j)];
                a[(i_global + i) * size + (offset + j)] = (a[(i_global + i) * size + (offset + j)] - sum) / diag;
            }
        }
    }
}

kernel void lud_internal(global float* a, local float* temp_top, local float* temp_left, const int size, const int offset)
{
    int idx_x = get_global_id(0);
    int idx_y = get_global_id(1);

    int chunks_in_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx_x >= chunks_in_row || idx_y >= chunks_in_row) return;

    int chunk_idx = idx_y * chunks_in_row + idx_x;

    int i_global = offset + BLOCK_SIZE * (1 + chunk_idx / chunks_in_row);
    int j_global = offset + BLOCK_SIZE * (1 + chunk_idx % chunks_in_row);

    int i, j, k;

    // Load temp_top
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_top[i * BLOCK_SIZE + j] = a[(offset + i) * size + (j_global + j)];
        }
    }

    // Load temp_left
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_left[i * BLOCK_SIZE + j] = a[(i_global + i) * size + (offset + j)];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    float sum[BLOCK_SIZE];
    for (j = 0; j < BLOCK_SIZE; j++) sum[j] = 0.0f;

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (k = 0; k < BLOCK_SIZE; k++) {
            float left_val = temp_left[i * BLOCK_SIZE + k];
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum[j] += left_val * temp_top[k * BLOCK_SIZE + j];
            }
        }

        for (j = 0; j < BLOCK_SIZE; j++) {
            a[(i_global + i) * size + (j_global + j)] -= sum[j];
            sum[j] = 0.0f;
        }
    }
}
